 *
 * For time-with-cap with cap status, the penalty applies to secondaryValue (reps)
 * not the time, so this function isn't used for that case — see handleApplyPenalty.
 */
function calculatePenaltyScore(
	rawValue: number,
	percentage: number,
	scheme: string,
	scoreStatus?: string,
): number {
	// Time-with-cap capped scores are rep-based (secondary value)
	// Time-with-cap scored (finished) scores are time-based
	const isTime =
		scheme === "time-with-cap"
			? scoreStatus !== "cap"
			: isTimeBasedScheme(scheme as WorkoutScheme)

	if (isTime) {
		// Time-based: add percentage of time as penalty (more time = worse)
		return Math.round(rawValue + rawValue * (percentage / 100))
	}
	// Rep/count-based: deduct percentage (fewer reps = worse)
	return Math.max(0, Math.round(rawValue - rawValue * (percentage / 100)))
}

function VerificationControls({
	submission,
	event,
	competitionId,
	trackWorkoutId,
	logs,
}: VerificationControlsProps) {
	const router = useRouter()
	const verifyFn = useServerFn(verifySubmissionScoreFn)

	const [isAdjusting, setIsAdjusting] = useState(false)
	const [isPenalizing, setIsPenalizing] = useState(false)
	const [isSubmitting, setIsSubmitting] = useState(false)
	const [error, setError] = useState<string | null>(null)

	// Adjust form state
	const [adjustedScore, setAdjustedScore] = useState(
		submission.score.displayValue,
	)
	const [adjustedStatus, setAdjustedStatus] = useState<"scored" | "cap">(
		submission.score.status === "cap" ? "cap" : "scored",
	)
	const [secondaryScore, setSecondaryScore] = useState(
		submission.score.secondaryValue !== null
			? String(submission.score.secondaryValue)

const verifySubmissionScoreInputSchema = z.object({
	competitionId: z.string().min(1),
	trackWorkoutId: z.string().min(1),
	scoreId: z.string().min(1),
	action: z.enum(["verify", "adjust", "invalid"]),
	// Required only when action === "adjust"
	adjustedScore: z.string().optional(),
	adjustedScoreStatus: z.enum(["scored", "cap"]).optional(),
	secondaryScore: z.string().optional(),
	tieBreakScore: z.string().optional(),
	reviewerNotes: z.string().optional(),
	// Penalty fields (for "adjust" action with penalty)
	penaltyType: z.enum(["minor", "major"]).optional(),
	penaltyPercentage: z.number().min(0).max(100).optional(),
	noRepCount: z.number().int().min(0).optional(),
})

